from typing import List
import math

class Solution:
    def minTime(self, n: int, k: int, m: int, time: List[int], mul: List[float]) -> float:
        @cache
        def dp(i, j, t):
            if i == n:
                return 0
            if j == m:
                return math.inf
            if (i, j, t) in memo:
                return memo[(i, j, t)]
            res = math.inf
            for x in range(1, k + 1):
                if i + x <= n:
                    cross_time = max(time[i:i+x]) * mul[j]
                    return_time = 0
                    if x < k:
                        return_time = max(time[i+x]) * mul[(j + math.floor(cross_time)) % m]
                    res = min(res, cross_time + dp(i + x, (j + math.floor(cross_time)) % m, t + 1) + return_time)
            memo[(i, j, t)] = res
            return res

        memo = {}
        return dp(0, 0, 0) if dp(0, 0, 0) != math.inf else -1
